    public static int getButton(int gui, int page, int x, int y) {
        for (int i = 0; i < BUTTON[gui][page].length; ++i) {
            if (x < BUTTON[gui][page][i][0] || y < BUTTON[gui][page][i][1] || x > BUTTON[gui][page][i][2] || y > BUTTON[gui][page][i][3]) continue;
            return i;
        }
        return -1;
    }

    public static int getBonusPointColor(int level) {
        int max = ConfigHandler.modernLimit;
        int color = 0;
        float flv = (float)level / (float)max - 0.5f;
        if (flv >= 0.5f) {
            return 0xFF0000;
        }
        color = flv >= 0.0f ? (int)(255.0f * (1.0f - flv * 2.0f)) * 256 + 0xFF0000 : (int)(255.0f * (1.0f - (flv += 0.5f) * 2.0f)) + 0xFFFF00;
        return color;
    }

    public static int getDarkerColor(int color, float dark) {
        float b = (color & 0xFF) * dark;
        float g = ((color >>= 8) & 0xFF) * dark;
        float r = (color >>= 8) * dark;
        return ((int)r << 16) + ((int)g << 8) + (int)b;
    }
